// Endpoint to handle the user's login and consent decision
app.post('/authorize/decision', (req, res) => {
    const { client_id, redirect_uri, state, username, password } = req.body;

    // Simulate user authentication
    // In a real system, validate against user database
    if (!username || !password) {
        // Redirect to redirect_uri with an error
        const errorRedirectUrl = new URL(redirect_uri);
        errorRedirectUrl.searchParams.set('error', 'access_denied');
        errorRedirectUrl.searchParams.set('error_description', 'User login failed or denied access.');
        if (state) errorRedirectUrl.searchParams.set('state', state);
        return res.redirect(errorRedirectUrl.toString());
    }

    // For this example, any username/password combination is considered "logged in".
    const user_id = username; // Use username as a simplified user_id

    // 4. Generate an authorization code
    const authCode = generateRandomString(32);
    const codeExpirySeconds = 300; // Code expires in 5 minutes
    authorizationCodes.set(authCode, {
        client_id: client_id,
        redirect_uri: redirect_uri,
        user_id: user_id,
        expires_at: getExpiryTime(codeExpirySeconds),
    });

    // 5. Redirect back to the client's redirect_uri with the code and state
    const redirectUrl = new URL(redirect_uri);
    redirectUrl.searchParams.set('code', authCode);
    if (state) {
        redirectUrl.searchParams.set('state', state);
    }
    res.redirect(redirectUrl.toString());
});

// --- Token Endpoint ---
// Exchanges an authorization code for an access token
// POST /token
app.post('/token', (req, res) => {
    const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

    // 1. Validate grant_type
    if (grant_type !== 'authorization_code') {
        return res.status(400).json({ error: 'unsupported_grant_type' });
    }

    // 2. Validate client_id and client_secret
    const client = clients.find(c => c.client_id === client_id && c.client_secret === client_secret);
    if (!client) {
        return res.status(401).json({ error: 'invalid_client', error_description: 'Client authentication failed.' });
    }

    // 3. Validate authorization code
    const storedCode = authorizationCodes.get(code);
    if (!storedCode) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code is invalid or expired.' });
    }

    // 4. Check if the code has expired
    if (storedCode.expires_at < Date.now()) {
        authorizationCodes.delete(code); // Clean up expired code
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code is expired.' });
    }

    // 5. Validate that the client_id and redirect_uri associated with the code match
    if (storedCode.client_id !== client_id || storedCode.redirect_uri !== redirect_uri) {
        return res.status(400).json({ error: 'invalid_grant', error_description: 'Authorization code mismatch (client_id or redirect_uri).' });
    }

    // 6. The authorization code can only be used once. Invalidate it immediately.
    authorizationCodes.delete(code);

    // 7. Generate an access token
    const accessToken = generateRandomString(64);
    const expiresInSeconds = 3600; // Token expires in 1 hour
    const refreshToken = generateRandomString(64); // Optional: Generate a refresh token

    accessTokens.set(accessToken, {
        client_id: client_id,
        user_id: storedCode.user_id,
        expires_at: getExpiryTime(expiresInSeconds),
    });

    // 8. Return the access token
    res.json({
        access_token: accessToken,
        token_type: 'Bearer',
        expires_in: expiresInSeconds,
        refresh_token: refreshToken, // Include refresh token if implemented
    });
});

